use rich_rust::prelude::*;

pub struct StatsDashboard<'a> {
    stats: &'a ArchiveStats,
    theme: &'a Theme,
}

impl<'a> StatsDashboard<'a> {
    pub fn new(stats: &'a ArchiveStats, theme: &'a Theme) -> Self {
        Self { stats, theme }
    }

    pub fn render(&self, output: &Output) {
        if !output.is_styled() {
            self.render_plain(output);
            return;
        }

        self.render_styled(output);
    }

    fn render_styled(&self, output: &Output) {
        // Overview Panel
        self.render_overview_panel(output);

        // Content Breakdown
        self.render_content_breakdown(output);

        // Storage Panel
        self.render_storage_panel(output);

        // Index Health Panel
        self.render_index_health(output);
    }

    fn render_overview_panel(&self, output: &Output) {
        let date_range = match (self.stats.date_range_start, self.stats.date_range_end) {
            (Some(start), Some(end)) => format!(
                "{} to {}",
                start.format("%Y-%m-%d"),
                end.format("%Y-%m-%d")
            ),
            _ => "Unknown".to_string(),
        };

        let mut table = Table::new()
            .title("📊 Archive Overview");

        table = table
            .with_column(Column::new("Metric"))
            .with_column(Column::new("Value").justify(JustifyMethod::Right));

        table.add_row_cells(["Archive Path", self.stats.archive_path.to_str().unwrap_or("?")]);
        table.add_row_cells(["Total Documents", &format_number(self.stats.total_documents)]);
        table.add_row_cells(["Date Range", &date_range]);
        table.add_row_cells(["Total Size", &humanize_bytes(self.stats.total_size_bytes())]);

        output.print_renderable(&table);
    }

    fn render_content_breakdown(&self, output: &Output) {
        let total = self.stats.total_documents as f64;

        let mut table = Table::new()
            .title("📝 Content Breakdown");

        table = table
            .with_column(Column::new("Type"))
            .with_column(Column::new("Count").justify(JustifyMethod::Right))
            .with_column(Column::new("%").justify(JustifyMethod::Right))
            .with_column(Column::new("Bar"));

        let types = [
            ("Tweets", self.stats.tweet_count, self.theme.primary),
            ("Likes", self.stats.like_count, self.theme.error),
            ("DMs", self.stats.dm_count, self.theme.secondary),
            ("Grok", self.stats.grok_count, self.theme.accent),
        ];

        let max_count = types.iter().map(|(_, c, _)| *c).max().unwrap_or(1);

        for (name, count, _color) in types {
            let pct = format_percentage(count as f64, total);
            let bar_len = if max_count > 0 {
                (count as f64 / max_count as f64 * 20.0) as usize
            } else {
                0
            };
            let bar = "█".repeat(bar_len);

            table.add_row_cells([name, &format_number(count), &pct, &bar]);
        }

        output.print_renderable(&table);
    }

    fn render_storage_panel(&self, output: &Output) {
        let mut table = Table::new()
            .title("💾 Storage");

        table = table
            .with_column(Column::new("Component"))
            .with_column(Column::new("Size").justify(JustifyMethod::Right))
            .with_column(Column::new("%").justify(JustifyMethod::Right));

        let total = self.stats.total_size_bytes() as f64;

        let components = [
            ("Archive", self.stats.archive_size_bytes),
            ("Index", self.stats.index_size_bytes),
            ("Database", self.stats.database_size_bytes),
        ];

        for (name, size) in components {
            let pct = format_percentage(size as f64, total);
            table.add_row_cells([name, &humanize_bytes(size), &pct]);
        }

        table.add_row_cells(["Total", &humanize_bytes(self.stats.total_size_bytes()), "100%"]);

        output.print_renderable(&table);
    }

    fn render_index_health(&self, output: &Output) {
        let coverage = self.stats.index_coverage_pct();
        let status_icon = if coverage >= 100.0 {
            format!("[{}]✓[/]", self.theme.success)
        } else if coverage >= 90.0 {
            format!("[{}]⚠[/]", self.theme.warning)
        } else {
            format!("[{}]✗[/]", self.theme.error)
        };

        let last_updated = self.stats.index_last_updated
            .map(|dt| dt.format("%Y-%m-%d %H:%M").to_string())
            .unwrap_or_else(|| "Never".to_string());

        let content = format!(
            "{} [{}]Index Status[/]\n\n\
            Documents indexed: {}/{} ({:.1}%)\n\
            Embeddings: {}\n\
            Last updated: {}",
            status_icon,
            self.theme.heading,
            format_number(self.stats.index_doc_count),
            format_number(self.stats.total_documents),
            coverage,
            format_number(self.stats.embedding_count),
            last_updated
        );

        let border_color = if coverage >= 100.0 {
            self.theme.success
        } else if coverage >= 90.0 {
            self.theme.warning
        } else {
            self.theme.error
        };

        let panel = Panel::from_text(&content)
            .title("🔍 Index Health")
            .border_style(border_color);

        output.print_renderable(&panel);
    }

    fn render_plain(&self, output: &Output) {
        println!("=== Archive Statistics ===");
        println!();
        println!("Archive: {}", self.stats.archive_path.display());
        println!("Total Documents: {}", format_number(self.stats.total_documents));
        println!();

        println!("Content Breakdown:");
        println!("  Tweets: {} ({:.1}%)", 
